import logging
import logging.handlers

# Set up file handlers for application logs
file_handler = logging.FileHandler('/var/log/application/')
file_handler.setLevel(logging.INFO)
file_handler.setFormatter(logging.Formatter('%(asctime)s - %(name)s - %(levelname)s - %(message)s'))

# Set up log rotation for the file handlers
file_rotator = logging.handlers.RotatingFileHandler('/var/log/application/', 'a', 1024 * 1024, 5)
file_rotator.setLevel(logging.INFO)
file_rotator.setFormatter(logging.Formatter('%(asctime)s - %(name)s - %(levelname)s - %(message)s'))

# Set up the root logger to use the file handlers
root = logging.getLogger()
root.setLevel(logging.INFO)
root.addHandler(file_handler)
root.addHandler(file_rotator)